1	interface Item {
2	  type: string;
3	}
4	
5	interface Step {
6	  type: string;
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  steps: Step[];
12	}
13	
14	const PROCESSING_FEE = 5;
15	const FIRST_INSURANCE_RATE = 0.1;
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	const COMPONENT_TYPES = new Set(["rune"]);
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	function calculateBasePremium(items: Item[]): number {
30	  const typeCounts: Record<string, number> = {};
31	  for (const item of items) {
32	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
33	  }
34	
35	  let total = 0;
36	  for (const [type, count] of Object.entries(typeCounts)) {
37	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
38	      total += BLOCK_PREMIUM;
39	    } else {
40	      total += count * BASE_PREMIUM[type];
41	    }
42	  }
43	  return total;
44	}
45	
46	export function processScenario(scenario: Scenario): unknown {
47	  const items = scenario.steps[0].items;
48	  const basePremium = calculateBasePremium(items);
49	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
50	  const premium = Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
51	
52	  return [{ premium }];
53	}
